#include<bits/stdc++.h>
using namespace std;
vector<pair<long long,long long>> mp[5010];
long long dis[5010],dis2[5010];
void dijkstra()
{
    memset(dis,0x3f,sizeof(dis));
    memset(dis2,0x3f,sizeof(dis2));
    dis[1]=0;
    priority_queue<pair<long long,long long>> q;
    q.push(make_pair(0,1));
    while(!q.empty())
    {
        long long t=q.top().second,d=(-(q.top().first));
        q.pop();
        if(d>dis2[t])
        {
            continue;
        }
        for(auto i:mp[t])
        {
            long long v=i.first,val=i.second;
            if(dis[v]>d+val)
            {
                dis2[v]=dis[v];
                dis[v]=d+val;
                q.push(make_pair(-dis[v],v));
            }
            else if(dis[v]!=d+val&&dis2[v]>d+val)
            {
                dis2[v]=d+val;
                q.push(make_pair(-dis2[v],v));
            }
        }
    }
}
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=m;i++)
    {
        long long u,v,w;
        scanf("%lld%lld%lld",&u,&v,&w);
        mp[u].push_back(make_pair(v,w));
        mp[v].push_back(make_pair(u,w));
    }
    dijkstra();
    printf("%lld",dis2[n]);
    return 0;
}
